import csv
import json
import logging
import sys
from datetime import datetime
from pathlib import Path
from typing import Dict, Any, List, Optional, Tuple

from code.src.utils.logger import get_default_logger, get_error_message

logger = get_default_logger("evaluation")


def load_synthetic_summaries(path: Path) -> List[Dict[str, Any]]:
    """Load synthetic summaries generated by T026."""
    if not path.exists():
        raise FileNotFoundError(f"Synthetic summaries file not found: {path}")
    with open(path, "r", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        return list(reader)


def load_ground_truth(path: Path) -> List[Dict[str, Any]]:
    """Load ground truth labels generated by T026."""
    if not path.exists():
        raise FileNotFoundError(f"Ground truth file not found: {path}")
    with open(path, "r", encoding="utf-8") as f:
        reader = csv.DictReader(f)
        return list(reader)


def load_audit_records(path: Path) -> List[Dict[str, Any]]:
    """Load audit records produced by the validator (T025)."""
    if not path.exists():
        raise FileNotFoundError(f"Audit records file not found: {path}")
    with open(path, "r", encoding="utf-8") as f:
        data = json.load(f)
        # Handle both list format and dict with 'records' key
        if isinstance(data, dict) and "records" in data:
            return data["records"]
        return data


def validate_summary(
    summary: Dict[str, Any], ground_truth: Dict[str, Any]
) -> Tuple[bool, bool]:
    """
    Compare a synthetic summary's reported inconsistency flag against ground truth.

    Returns:
        (is_inconsistent_reported, is_actually_inconsistent)
    """
    # Ground truth usually has a boolean or 'inconsistent' string
    gt_val = ground_truth.get("is_inconsistent", False)
    is_actually_inconsistent = (
        gt_val is True or str(gt_val).lower() in ("true", "1", "yes", "inconsistent")
    )

    # Summary might have a flag set by the validator
    summary_val = summary.get("is_inconsistent", summary.get("flagged", False))
    is_inconsistent_reported = (
        summary_val is True or str(summary_val).lower() in ("true", "1", "yes", "inconsistent")
    )

    return is_inconsistent_reported, is_actually_inconsistent


def evaluate_detection(
    synthetic_summaries: List[Dict[str, Any]],
    ground_truth: List[Dict[str, Any]],
    audit_records: List[Dict[str, Any]],
) -> Dict[str, float]:
    """
    Compute precision, recall, and F1 for the inconsistency detection component.

    Precision = TP / (TP + FP)
    Recall    = TP / (TP + FN)
    F1        = 2 * (Precision * Recall) / (Precision + Recall)
    """
    if len(synthetic_summaries) != len(ground_truth):
        raise ValueError(
            f"Synthetic summaries ({len(synthetic_summaries)}) and "
            f"ground truth ({len(ground_truth)}) must have the same length."
        )

    # Map ground truth by a unique ID if available, otherwise by index
    gt_map = {}
    for i, gt in enumerate(ground_truth):
        key = gt.get("id") or gt.get("summary_id") or i
        gt_map[key] = gt

    tp, fp, fn, tn = 0, 0, 0, 0

    for i, summary in enumerate(synthetic_summaries):
        key = summary.get("id") or summary.get("summary_id") or i
        if key not in gt_map:
            logger.warning(f"Missing ground truth for summary key: {key}")
            continue

        gt = gt_map[key]

        # Find corresponding audit record
        audit_rec = None
        for rec in audit_records:
            rec_key = rec.get("id") or rec.get("summary_id") or rec.get("url")
            if rec_key == key:
                audit_rec = rec
                break

        if audit_rec is None:
            # If no audit record exists for a synthetic summary, treat as "not flagged"
            # This is effectively a False Negative if the truth is inconsistent
            is_reported = False
        else:
            is_reported, is_actual = validate_summary(summary, gt)

            if is_reported and is_actual:
                tp += 1
            elif is_reported and not is_actual:
                fp += 1
            elif not is_reported and is_actual:
                fn += 1
            else:
                tn += 1

    precision = tp / (tp + fp) if (tp + fp) > 0 else 0.0
    recall = tp / (tp + fn) if (tp + fn) > 0 else 0.0
    f1 = (
        2 * (precision * recall) / (precision + recall)
        if (precision + recall) > 0
        else 0.0
    )

    return {
        "precision": precision,
        "recall": recall,
        "f1": f1,
        "true_positives": tp,
        "false_positives": fp,
        "false_negatives": fn,
        "true_negatives": tn,
    }


def write_evaluation_results(
    metrics: Dict[str, float], output_path: Path, thresholds: Dict[str, float]
) -> None:
    """Write evaluation metrics to a JSON file and log results."""
    result = {
        "timestamp": datetime.utcnow().isoformat() + "Z",
        "metrics": metrics,
        "thresholds": thresholds,
        "passed": (
            metrics["precision"] >= thresholds.get("precision", 0.90)
            and metrics["recall"] >= thresholds.get("recall", 0.80)
        ),
    }

    output_path.parent.mkdir(parents=True, exist_ok=True)
    with open(output_path, "w", encoding="utf-8") as f:
        json.dump(result, f, indent=2)

    logger.info(f"Evaluation results written to {output_path}")
    logger.info(f"Precision: {metrics['precision']:.4f} (threshold: {thresholds['precision']})")
    logger.info(f"Recall:    {metrics['recall']:.4f} (threshold: {thresholds['recall']})")
    logger.info(f"F1 Score:  {metrics['f1']:.4f}")

    if not result["passed"]:
        logger.error(get_error_message("ERR-800"))
        raise RuntimeError(
            f"Evaluation failed thresholds. Precision={metrics['precision']:.4f}, "
            f"Recall={metrics['recall']:.4f}. Thresholds: P>={thresholds['precision']}, "
            f"R>={thresholds['recall']}. ERR-800 raised."
        )


def main() -> None:
    """Main entry point for T029: Evaluate inconsistency detection on synthetic data."""
    # Paths relative to project root
    project_root = Path(__file__).resolve().parent.parent.parent.parent
    synthetic_path = project_root / "data" / "synthetic" / "synthetic_summaries.csv"
    ground_truth_path = project_root / "data" / "synthetic" / "ground_truth.csv"
    audit_report_path = project_root / "output" / "audit_report.json"
    output_path = project_root / "output" / "synthetic_evaluation_results.json"

    # Thresholds per FR-031 / SC-030
    thresholds = {"precision": 0.90, "recall": 0.80}

    logger.info("Starting synthetic validation evaluation (T029)...")

    try:
        synthetic_summaries = load_synthetic_summaries(synthetic_path)
        ground_truth = load_ground_truth(ground_truth_path)
        audit_records = load_audit_records(audit_report_path)

        if not synthetic_summaries:
            raise ValueError("No synthetic summaries found.")
        if not ground_truth:
            raise ValueError("No ground truth found.")
        if not audit_records:
            raise ValueError("No audit records found.")

        metrics = evaluate_detection(synthetic_summaries, ground_truth, audit_records)
        write_evaluation_results(metrics, output_path, thresholds)

        logger.info("T029 completed successfully.")
        sys.exit(0)

    except FileNotFoundError as e:
        logger.error(f"Data file missing: {e}")
        sys.exit(1)
    except RuntimeError as e:
        logger.error(str(e))
        sys.exit(1)
    except Exception as e:
        logger.exception(f"Unexpected error during evaluation: {e}")
        sys.exit(1)


if __name__ == "__main__":
    main()